const CronManager = require('./manager');
const { NOOP } = require('../../constants');

/**
 * Creates CronManager instance
 * @param {{jobConfigs: Array, startNow?: boolean, onTick?: ({key: string, value: any}) => void}} options
 */
function createCronManager({ jobConfigs, startNow = false, onTick = NOOP }) {
  const cronManager = new CronManager({ onTick });

  jobConfigs.forEach(cronManager.addJob.bind(cronManager));

  if (startNow) {
    cronManager.start();
  }

  return cronManager;
}

module.exports = {
  createCronManager,
};
